// postCron.js
const cron = require('cron');
const crawler = require('./crawler'); // Import scraper

// Take client as a parameter
const postCron = (client) => {
  // Build the job
  const job = new cron.CronJob('* * * * *', async () => {
    // Call the scraper
    const data = await crawler();
    // Generate a random index
    const randomIndex = Math.floor(Math.random() * data.length);
    // Get the random data
    const randomData = data[randomIndex];
    // Get the channel
    const channel = client.channels.cache.get('Channel ID'); // You can change Channel ID to process.env.DISCORD_CHANNEL_ID
    // Send message
    await channel.send(`Daily 9 PM random recommendation from Ray: [${randomData.title}](${randomData.url})`);
  });

  // Return the job
  return job;
}


module.exports = postCron;

